/**
 * Pure builder that turns an `AgentDefinition` into the `.canopy/`,
 * `.mulch/`, `.seeds/`, `.pi/` workspace drops (SPEC §4.3 step 3, §11.A).
 *
 * Returns `HttpWorkspaceFile[]` with workspace-relative paths so the
 * caller can either thread the list into `HttpClient.burrows.up({ seed })`
 * (R-07 atomic provision-and-seed) or post-provision via
 * `HttpClient.files.write`. No side effects — same validation errors as
 * the prior writer, but the disk writes themselves move to the caller.
 *
 * Five drops:
 *
 *   `.canopy/agent.json` — the rendered AgentDefinition envelope. The
 *      harness (claude-code or sapling) reads whichever sections it
 *      needs; packaging the whole envelope avoids prematurely freezing
 *      a per-section file layout before harness expectations stabilize.
 *
 *   `.mulch/expertise/<domain>.jsonl` — one entry per `expertise_seed`
 *      line, grouped by the line's `domain` field. Format is canonical
 *      mulch record JSONL; bad lines (non-JSON, missing `domain`) throw
 *      `RunSpawnError` so the operator sees the schema break before the
 *      run starts.
 *
 *   `.seeds/workflow.txt` — the workflow body verbatim. Seeds tooling
 *      consumes it; warren is just the courier.
 *
 *   `.pi/skills/<name>/SKILL.md` — one file per `pi_skills` JSONL line
 *      `{name, body}`. Pi reads SKILL.md from each skill directory; the
 *      canopy section is one envelope-per-line so a single canopy
 *      section can ship many skills without inventing a new artifact
 *      type. Bad lines (non-JSON, missing/invalid `name` or `body`)
 *      throw `RunSpawnError`.
 *
 *   `.pi/prompts/<name>.md` — same JSONL `{name, body}` shape as
 *      pi_skills but flat (one .md per prompt, no per-prompt
 *      directory).
 *
 *   `.pi/extensions/<name>.ts` — same JSONL `{name, body}` shape as
 *      pi_prompts but flat .ts modules (extensions default-export a
 *      `(pi) => {…}` registration function). INERT until burrow drops
 *      `--no-extensions` for pi-chat; seeding alone is a no-op.
 */

import type { HttpWorkspaceFile } from "@os-eco/burrow-cli";
import type { AgentDefinition } from "../registry/schema.ts";
import { RunSpawnError } from "./errors.ts";

export type { HttpWorkspaceFile } from "@os-eco/burrow-cli";

export interface BuildSeedFilesResult {
	readonly files: readonly HttpWorkspaceFile[];
	readonly canopyPath: string;
	readonly mulchDomains: readonly string[];
	readonly workflowPath: string | null;
	readonly piSkills: readonly string[];
	readonly piPrompts: readonly string[];
	readonly piExtensions: readonly string[];
}

export function buildSeedFiles(agent: AgentDefinition): BuildSeedFilesResult {
	const files: HttpWorkspaceFile[] = [];

	const canopyPath = ".canopy/agent.json";
	files.push({
		path: canopyPath,
		contents: `${JSON.stringify(
			{
				name: agent.name,
				version: agent.version,
				sections: agent.sections,
				resolvedFrom: agent.resolvedFrom,
				frontmatter: agent.frontmatter,
			},
			null,
			2,
		)}\n`,
	});

	const { domains, files: mulchFiles } = buildExpertiseFiles(agent.sections.expertise_seed);
	files.push(...mulchFiles);

	const workflowFile = buildWorkflowFile(agent.sections.workflow);
	if (workflowFile !== null) files.push(workflowFile);

	const { names: piSkills, files: skillFiles } = buildPiArtifactFiles(
		agent.sections.pi_skills,
		"skill",
	);
	files.push(...skillFiles);

	const { names: piPrompts, files: promptFiles } = buildPiArtifactFiles(
		agent.sections.pi_prompts,
		"prompt",
	);
	files.push(...promptFiles);

	const { names: piExtensions, files: extensionFiles } = buildPiArtifactFiles(
		agent.sections.pi_extensions,
		"extension",
	);
	files.push(...extensionFiles);

	return {
		files,
		canopyPath,
		mulchDomains: domains,
		workflowPath: workflowFile?.path ?? null,
		piSkills,
		piPrompts,
		piExtensions,
	};
}

function buildExpertiseFiles(body: string | undefined): {
	domains: readonly string[];
	files: HttpWorkspaceFile[];
} {
	if (body === undefined || body.trim() === "") return { domains: [], files: [] };

	const grouped = new Map<string, string[]>();
	const lines = body.split("\n");
	for (let i = 0; i < lines.length; i++) {
		const raw = lines[i];
		if (raw === undefined) continue;
		const line = raw.trim();
		if (line === "") continue;
		let parsed: unknown;
		try {
			parsed = JSON.parse(line);
		} catch (err) {
			throw new RunSpawnError(
				`expertise_seed line ${i + 1} is not valid JSON: ${formatError(err)}`,
				{ recoveryHint: "fix the canopy prompt's expertise_seed section" },
			);
		}
		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			throw new RunSpawnError(
				`expertise_seed line ${i + 1} is not a JSON object: ${truncate(line, 80)}`,
			);
		}
		const domain = (parsed as { domain?: unknown }).domain;
		if (typeof domain !== "string" || domain === "") {
			throw new RunSpawnError(`expertise_seed line ${i + 1} is missing a non-empty "domain" field`);
		}
		const bucket = grouped.get(domain) ?? [];
		bucket.push(line);
		grouped.set(domain, bucket);
	}

	const domains = [...grouped.keys()].sort();
	const files = domains.map((domain) => {
		const records = grouped.get(domain) ?? [];
		return { path: `.mulch/expertise/${domain}.jsonl`, contents: `${records.join("\n")}\n` };
	});
	return { domains, files };
}

function buildWorkflowFile(body: string | undefined): HttpWorkspaceFile | null {
	if (body === undefined || body.trim() === "") return null;
	return {
		path: ".seeds/workflow.txt",
		contents: body.endsWith("\n") ? body : `${body}\n`,
	};
}

type PiArtifactKind = "skill" | "prompt" | "extension";

function buildPiArtifactFiles(
	body: string | undefined,
	kind: PiArtifactKind,
): { names: readonly string[]; files: HttpWorkspaceFile[] } {
	if (body === undefined || body.trim() === "") return { names: [], files: [] };
	const sectionName = PI_ARTIFACT_SECTION[kind];

	const entries: Array<{ name: string; body: string }> = [];
	const seen = new Set<string>();
	const lines = body.split("\n");
	for (let i = 0; i < lines.length; i++) {
		const raw = lines[i];
		if (raw === undefined) continue;
		const line = raw.trim();
		if (line === "") continue;
		let parsed: unknown;
		try {
			parsed = JSON.parse(line);
		} catch (err) {
			throw new RunSpawnError(
				`${sectionName} line ${i + 1} is not valid JSON: ${formatError(err)}`,
				{ recoveryHint: `fix the canopy prompt's ${sectionName} section` },
			);
		}
		if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
			throw new RunSpawnError(
				`${sectionName} line ${i + 1} is not a JSON object: ${truncate(line, 80)}`,
			);
		}
		const obj = parsed as { name?: unknown; body?: unknown };
		if (typeof obj.name !== "string" || obj.name === "") {
			throw new RunSpawnError(`${sectionName} line ${i + 1} is missing a non-empty "name" field`);
		}
		if (!isSafeArtifactName(obj.name)) {
			throw new RunSpawnError(
				`${sectionName} line ${i + 1} has unsafe "name" ${JSON.stringify(obj.name)} (no path separators, "." or "..")`,
			);
		}
		if (typeof obj.body !== "string") {
			throw new RunSpawnError(`${sectionName} line ${i + 1} is missing a string "body" field`);
		}
		if (seen.has(obj.name)) {
			throw new RunSpawnError(
				`${sectionName} line ${i + 1} duplicates name ${JSON.stringify(obj.name)}`,
			);
		}
		seen.add(obj.name);
		entries.push({ name: obj.name, body: obj.body });
	}

	if (entries.length === 0) return { names: [], files: [] };

	const files = entries.map((entry) => {
		return {
			path: piArtifactPath(kind, entry.name),
			contents: entry.body.endsWith("\n") ? entry.body : `${entry.body}\n`,
		};
	});
	const names = entries.map((e) => e.name).sort();
	return { names, files };
}

const PI_ARTIFACT_SECTION: Record<PiArtifactKind, string> = {
	skill: "pi_skills",
	prompt: "pi_prompts",
	extension: "pi_extensions",
};

function piArtifactPath(kind: PiArtifactKind, name: string): string {
	switch (kind) {
		case "skill":
			return `.pi/skills/${name}/SKILL.md`;
		case "prompt":
			return `.pi/prompts/${name}.md`;
		case "extension":
			return `.pi/extensions/${name}.ts`;
	}
}

function isSafeArtifactName(name: string): boolean {
	if (name === "." || name === "..") return false;
	if (name.includes("/") || name.includes("\\")) return false;
	if (name.includes("\0")) return false;
	return true;
}

function truncate(s: string, max: number): string {
	return s.length <= max ? s : `${s.slice(0, max)}…`;
}

function formatError(err: unknown): string {
	if (err instanceof Error) return err.message;
	return String(err);
}

import { join } from "node:path";
import type { BurrowClient } from "../../burrow-client/client.ts";
import { withTransportMapping } from "../../burrow-client/client.ts";
import type { EventRow, RunFailureReason, RunTerminalState } from "../../db/schema.ts";
import { openPullRequest } from "../pr.ts";
import { dispatchAutoPlanRuns, hasAutoPlanRunFrontmatter, parsePlanIds } from "./auto-plan-run.ts";
import { runWorkspaceDestroy } from "./destroy.ts";
import { mergeMulch } from "./mulch.ts";
import { mergePlot } from "./plot-merge.ts";
import { runPrOpen } from "./pr-open.ts";
import { runPreviewAnnotate, runPreviewLaunch } from "./preview.ts";
import { mirrorPlans, mirrorSeeds } from "./seeds.ts";
import { stagePlotForCommit, stageSeedsForCommit } from "./stage.ts";
import { inferFailureReason, isTerminal, transitionToTerminal } from "./state.ts";
import type { ReapRunInput, ReapRunResult, ReapStep, ReapStepError } from "./types.ts";
import {
	buildAlreadyTerminalResult,
	createSeqAllocator,
	defaultExec,
	defaultFs,
	isWorkspaceDirty,
} from "./util.ts";

export async function reapRun(input: ReapRunInput): Promise<ReapRunResult> {
	const fs = input.fs ?? defaultFs;
	const exec = input.exec ?? defaultExec;
	const now = input.now ?? (() => new Date());

	const run = await input.repos.runs.require(input.runId);
	if (isTerminal(run.state)) {
		input.logger?.info?.(
			{ runId: run.id, state: run.state },
			"reap skipped: run already in terminal state",
		);
		return buildAlreadyTerminalResult(run);
	}

	// State on entry is the discriminator: still `queued` means the bridge
	// never claimed it (no events flowed from burrow) — "never started" (warren-5e53).
	const stateOnEntry = run.state;

	// `run.projectId` is null when the project was deleted while the run
	// existed (warren-5f19): the FK is `ON DELETE SET NULL`, so the run
	// row survives as an orphan. We can still finalize the state, but the
	// mulch-merge, seeds-close, and branch-push sub-steps target the
	// project clone on disk, which is gone. Skip them and emit a system so
	// operators can see why reap was a no-op.
	const project = run.projectId !== null ? await input.repos.projects.get(run.projectId) : null;
	const seq = createSeqAllocator((await input.repos.events.maxSeqForRun(run.id)) ?? 0);
	const errors: ReapStepError[] = [];
	const emit = async (kind: string, payload: unknown): Promise<EventRow> => {
		const row = await input.repos.events.append({
			runId: run.id,
			burrowEventSeq: seq.next(),
			ts: now().toISOString(),
			kind,
			stream: "system",
			payload,
		});
		input.broker?.publish(run.id, row);
		return row;
	};
	const fail = async (step: ReapStep, err: unknown, path?: string): Promise<void> => {
		const message = err instanceof Error ? err.message : String(err);
		const stepError: ReapStepError =
			path !== undefined ? { step, message, path } : { step, message };
		errors.push(stepError);
		await emit("reap_failed", stepError);
		input.logger?.error?.({ runId: run.id, step, err: message, path }, "reap step failed");
	};

	let mulchUpdated = 0;
	let mulchSkipped = 0;
	let mulchAppended = 0;
	let seedsClosed = 0;
	let seedsCreated = 0;
	let plotEventsAppended = 0;
	let plotsUpdated = 0;
	let plotEventsMirrored = 0;
	let plotCommitted = false;
	let seedsCommitted = false;
	let branchPushed = false;
	let commitsAhead: number | null = null;
	let droppedCommit = false;
	let prUrl: string | null = null;
	let previewLaunchState: "live" | "failed" | null = null;
	let previewLaunchPort: number | null = null;
	let previewUrl: string | null = null;
	let autoPlanRunCreated = false;
	let autoPlanRunId: string | null = null;
	let autoPlanRunPlanId: string | null = null;

	let workspacePath: string | null = null;
	let branch: string | null = null;
	let workerClient: BurrowClient | null = null;
	if (run.burrowId === null) {
		await fail("workspace_lookup", new Error("run has no burrow_id; nothing to reap from"));
	} else {
		try {
			workerClient = (await input.burrowClientPool.clientFor({ burrowId: run.burrowId })).client;
			const burrow = await withTransportMapping(workerClient.config, () =>
				(workerClient as BurrowClient).http.burrows.get(run.burrowId as string),
			);
			workspacePath = burrow.workspacePath;
			branch = typeof burrow.branch === "string" && burrow.branch !== "" ? burrow.branch : null;
		} catch (err) {
			await fail("workspace_lookup", err);
		}
	}
	// Base branch for the empty-push count comes from the project row, not
	// burrow (which doesn't expose baseBranch at the top level). For V1 the
	// primary flow always carves the workspace branch off
	// `project.defaultBranch`, the correct ref for `rev-list --count`.
	const baseBranch: string | null = project?.defaultBranch ?? null;

	if (stateOnEntry === "queued" && workspacePath !== null && project !== null) {
		await emit("reap.never_started_skip", {
			message: "agent never ran; skipping workspace pipeline",
		});
	} else if (stateOnEntry !== "queued" && workspacePath !== null && project !== null) {
		try {
			const result = await mergeMulch(workspacePath, project.localPath, fs, emit, fail);
			mulchUpdated = result.updated;
			mulchSkipped = result.skipped;
			mulchAppended = result.appended;
		} catch (err) {
			await fail("mulch_merge", err);
		}

		try {
			// workerClient is set whenever workspacePath !== null (both land in
			// the same try-block above), so the cast is sound.
			const mirrorResult = await mirrorSeeds({
				burrowClient: workerClient as BurrowClient,
				burrowId: run.burrowId as string,
				projectPath: project.localPath,
				fs,
				emit,
			});
			seedsClosed = mirrorResult.closed;
			seedsCreated = mirrorResult.created;
		} catch (err) {
			await fail("seeds_close", err);
		}

		// warren-a32a: snapshot the project-clone baseline plans.jsonl BEFORE
		// mirrorPlans so auto_plan_run can diff workspace vs baseline. Must
		// happen here because mirrorPlans appends workspace plans into the
		// project clone, which would make the baseline identical to the
		// workspace and defeat the diff (warren-d9a2 ordering bug).
		let baselinePlanIds: Set<string> | null = null;
		if (project.hasSeeds && input.outcome === "succeeded" && hasAutoPlanRunFrontmatter(run)) {
			try {
				const baselineBody =
					(await fs.readFile(join(project.localPath, ".seeds", "plans.jsonl"))) ?? "";
				baselinePlanIds = parsePlanIds(baselineBody);
			} catch {
				// Non-fatal — detection failure degrades to no auto-dispatch.
			}
		}

		// warren-d9a2: mirror plans.jsonl from workspace → project clone,
		// same shape as mirrorSeeds above. Without this, stageSeedsForCommit
		// copies the OLD project baseline plans.jsonl into the workspace,
		// overwriting the agent's newly-created plans.
		try {
			await mirrorPlans({
				burrowClient: workerClient as BurrowClient,
				burrowId: run.burrowId as string,
				projectPath: project.localPath,
				fs,
				emit,
			});
		} catch (err) {
			await fail("plans_mirror", err);
		}

		try {
			const result = await mergePlot(workspacePath, project.localPath, fs, emit, fail);
			plotEventsAppended = result.eventsAppended;
			plotsUpdated = result.plotsUpdated;
			plotEventsMirrored = result.mirrored;
		} catch (err) {
			await fail("plot_merge", err);
		}

		// warren-343a / shape (a) commit-through-reap: replicate the merged
		// `.plot/` from the project clone into the workspace and author a
		// `chore(warren): plot state` commit when there's a staged delta the
		// agent never committed. This is the carrier for host-side appender
		// writes (defaultPlotAppender, defaultPlanRunPlotAppender,
		// autoTransitionPlotToDone — see SPEC §11.O) and for any
		// agent-emitted `.plot/` lines that the agent left uncommitted.
		// Skipped when the project has no `.plot/`. Best-effort: failures
		// emit `reap_failed` step=`plot_commit` and do not fail the run.
		if (project.hasPlot) {
			try {
				plotCommitted = await stagePlotForCommit({
					workspacePath,
					projectPath: project.localPath,
					fs,
					exec,
					emit,
				});
			} catch (err) {
				await fail("plot_commit", err, join(workspacePath, ".plot"));
			}
		}

		// warren-7ecc: seeds commit-through-reap. See stageSeedsForCommit.

		// warren-a32a: snapshot the workspace's plans.jsonl BEFORE
		// stageSeedsForCommit (which copies project→workspace). Baseline
		// was already captured above mirrorPlans.
		let workspacePlanIds: Set<string> | null = null;
		let workspacePlansBody: string | null = null;
		if (baselinePlanIds !== null) {
			try {
				workspacePlansBody =
					(await fs.readFile(join(workspacePath, ".seeds", "plans.jsonl"))) ?? "";
				workspacePlanIds = parsePlanIds(workspacePlansBody);
			} catch {
				// Non-fatal — detection failure degrades to no auto-dispatch.
			}
		}

		if (project.hasSeeds) {
			try {
				seedsCommitted = await stageSeedsForCommit({
					workspacePath,
					projectPath: project.localPath,
					fs,
					exec,
					emit,
				});
			} catch (err) {
				await fail("seeds_commit", err, join(workspacePath, ".seeds"));
			}
		}

		const autoDispatch = await dispatchAutoPlanRuns({
			run,
			project,
			workspacePlanIds,
			baselinePlanIds,
			workspacePlansBody,
			planRuns: input.repos.planRuns as unknown as {
				create: (i: unknown) => Promise<{ planRun: { id: string } }>;
			},
			emit,
			fail: (step, err) => fail(step, err),
			...(input.seedsCli !== undefined ? { seedsCli: input.seedsCli } : {}),
		});
		autoPlanRunCreated = autoDispatch.created;
		autoPlanRunId = autoDispatch.id;
		autoPlanRunPlanId = autoDispatch.planId;

		try {
			await exec.run("git", ["push", "origin", branch !== null ? `HEAD:${branch}` : "HEAD"], {
				cwd: workspacePath,
				timeoutMs: 60_000,
			});
			branchPushed = true;
		} catch (err) {
			await fail("branch_push", err, workspacePath);
		}

		// Empty-push observability (warren-f3bb): branchPushed alone can't
		// tell a real-work push from a no-op against an unchanged HEAD.
		// Count commits ahead of the project's defaultBranch; surface zero
		// as `reap.empty_push` and pin the count on `commitsAhead`. rev-list
		// failures are non-fatal — they degrade to `commitsAhead: null`.
		if (branchPushed && baseBranch !== null) {
			try {
				const out = await exec.run("git", ["rev-list", "--count", `${baseBranch}..HEAD`], {
					cwd: workspacePath,
					timeoutMs: 10_000,
				});
				const parsed = Number.parseInt(out.stdout.trim(), 10);
				commitsAhead = Number.isFinite(parsed) ? parsed : null;
			} catch (err) {
				input.logger?.info?.(
					{ runId: run.id, err: err instanceof Error ? err.message : String(err) },
					"reap commits-ahead count failed; continuing",
				);
			}
			if (commitsAhead === 0) {
				// warren-72b9: dirty tree + zero commits = staged-but-uncommitted.
				const dirty = await isWorkspaceDirty(exec, workspacePath);
				droppedCommit = dirty && input.outcome === "succeeded";
				await emit("reap.empty_push", {
					branch,
					baseBranch,
					dirty,
					droppedCommit,
					message: dirty
						? "git push exited zero and the workspace still has uncommitted changes — agent staged work but never committed"
						: "git push exited zero but the branch landed no new commits — agent did not commit",
				});
			}
		}

		// Auto-open PR (warren-f6af). See runPrOpen for the gate semantics.
		if (
			input.autoOpenPr?.enabled === true &&
			input.outcome === "succeeded" &&
			branchPushed &&
			commitsAhead !== null &&
			commitsAhead > 0 &&
			branch !== null &&
			branch !== project.defaultBranch
		) {
			prUrl = await runPrOpen({
				autoOpen: input.autoOpenPr,
				project,
				run,
				branch,
				baseBranch,
				workspacePath: workspacePath as string,
				previewOptedIn: input.previewConfig !== undefined,
				exec,
				emit,
				fail: (step, err) => fail(step, err),
				setPrUrl: (id, url) => input.repos.runs.setPrUrl(id, url),
				openPr: input.openPr ?? openPullRequest,
				...(input.prTemplate !== undefined ? { prTemplate: input.prTemplate } : {}),
				...(input.sleep !== undefined ? { sleep: input.sleep } : {}),
			});
		}

		// Preview launch (warren-f156 / SPEC §11.L). See runPreviewLaunch +
		// runPreviewAnnotate for the gate semantics. Skipped on a dropped
		// commit (warren-72b9).
		if (
			input.outcome === "succeeded" &&
			!droppedCommit &&
			input.previewConfig !== undefined &&
			input.portAllocator !== undefined &&
			workerClient !== null &&
			run.burrowId !== null
		) {
			const pv = await runPreviewLaunch({
				runId: run.id,
				burrowId: run.burrowId,
				workerId: run.workerId,
				outcome: input.outcome,
				previewConfig: input.previewConfig,
				portAllocator: input.portAllocator,
				workerClient,
				repos: input.repos,
				now,
				emit,
				fail,
				...(input.launchPreview !== undefined ? { launchPreviewFn: input.launchPreview } : {}),
			});
			previewLaunchState = pv.state;
			previewLaunchPort = pv.port;
		}

		if (
			prUrl !== null &&
			previewLaunchState !== null &&
			input.autoOpenPr?.enabled === true &&
			input.autoOpenPr.token !== ""
		) {
			previewUrl = await runPreviewAnnotate({
				runId: run.id,
				prUrl,
				previewLaunchState,
				autoOpenPr: input.autoOpenPr,
				previewLaunchConfig: input.previewLaunchConfig,
				repos: input.repos,
				emit,
				fail,
				...(input.annotatePrPreview !== undefined
					? { annotatePrPreviewFn: input.annotatePrPreview }
					: {}),
			});
		}
	} else if (workspacePath !== null && project === null) {
		await emit("reap.orphaned", {
			projectId: run.projectId,
			message: "project was deleted; skipping mulch merge, seeds close, and branch push",
		});
	}

	// warren-72b9: `droppedCommit` flips an otherwise-succeeded run to
	// `failed`/`dropped_commit` so it can't masquerade as success.
	const effectiveOutcome: RunTerminalState = droppedCommit ? "failed" : input.outcome;

	let failureReason: RunFailureReason | null = null;
	if (droppedCommit) {
		failureReason = "dropped_commit";
	} else if (effectiveOutcome === "failed") {
		failureReason =
			input.failureReason ?? (await inferFailureReason(input.repos, run.id, stateOnEntry));
	}

	const finalState = await transitionToTerminal(
		input.repos,
		run.id,
		stateOnEntry,
		effectiveOutcome,
		now(),
		failureReason,
	);

	await emit("reap.completed", {
		state: finalState,
		failureReason,
		mulch: { updated: mulchUpdated, skipped: mulchSkipped, appended: mulchAppended },
		seeds: { closed: seedsClosed, created: seedsCreated, committed: seedsCommitted },
		plot: {
			eventsAppended: plotEventsAppended,
			plotsUpdated,
			mirrored: plotEventsMirrored,
			committed: plotCommitted,
		},
		branchPushed,
		commitsAhead,
		prUrl,
		previewState: previewLaunchState,
		previewPort: previewLaunchPort,
		previewUrl,
		autoPlanRun: { created: autoPlanRunCreated, id: autoPlanRunId, planId: autoPlanRunPlanId },
		errors,
	});

	// Final sub-step (warren-0d89): destroy the burrow workspace now that
	// every result has been extracted and the branch pushed. Best-effort —
	// skipped for conversation runs and still-live previews, and a failure
	// surfaces as `reap_failed` step=`workspace_destroy` without blocking
	// the terminal-state transition above.
	const workspaceDestroyed = await runWorkspaceDestroy({
		run,
		previewLaunchState,
		workerClient,
		repos: input.repos,
		emit,
		fail: (step, err) => fail(step, err),
	});

	if (input.broker !== undefined) input.broker.close(run.id);

	input.logger?.info?.(
		{
			runId: run.id,
			state: finalState,
			failureReason,
			mulchUpdated,
			mulchSkipped,
			mulchAppended,
			seedsClosed,
			seedsCreated,
			seedsCommitted,
			plotEventsAppended,
			plotsUpdated,
			plotEventsMirrored,
			plotCommitted,
			branchPushed,
			commitsAhead,
			prUrl,
			previewState: previewLaunchState,
			previewPort: previewLaunchPort,
			previewUrl,
			autoPlanRunCreated,
			autoPlanRunId,
			workspaceDestroyed,
			errored: errors.length > 0,
		},
		"reap completed",
	);

	return {
		state: finalState,
		failureReason,
		mulchUpdated,
		mulchSkipped,
		mulchAppended,
		seedsClosed,
		seedsCreated,
		plotEventsAppended,
		plotsUpdated,
		plotEventsMirrored,
		plotCommitted,
		seedsCommitted,
		branchPushed,
		commitsAhead,
		prUrl,
		previewState: previewLaunchState,
		previewPort: previewLaunchPort,
		previewUrl,
		autoPlanRunCreated,
		autoPlanRunId,
		autoPlanRunPlanId,
		workspaceDestroyed,
		errors,
		alreadyTerminal: false,
	};
}

import { dirname, join } from "node:path";
import { NotFoundError } from "@os-eco/burrow-cli";
import type { BurrowClient } from "../../burrow-client/client.ts";
import { withTransportMapping } from "../../burrow-client/client.ts";
import type { EventRow } from "../../db/schema.ts";
import type { ReapFs } from "./types.ts";
import { splitLines } from "./util.ts";

/* ----------------------------------------------------------------------- */
/* Seeds close mirror                                                       */
/* ----------------------------------------------------------------------- */

interface SeedRow {
	id: string;
	status: string;
	updatedAt: string;
	raw: string;
}

interface MirrorClosedSeedsInput {
	readonly burrowClient: BurrowClient;
	readonly burrowId: string;
	readonly projectPath: string;
	readonly fs: ReapFs;
	readonly emit: (kind: string, payload: unknown) => Promise<EventRow>;
}

interface MirrorSeedsResult {
	readonly closed: number;
	readonly created: number;
}

export async function mirrorSeeds(input: MirrorClosedSeedsInput): Promise<MirrorSeedsResult> {
	const { burrowClient, burrowId, projectPath, fs, emit } = input;
	const projectFile = join(projectPath, ".seeds", "issues.jsonl");

	let burrowBody: string;
	try {
		const out = await withTransportMapping(burrowClient.config, () =>
			burrowClient.http.files.read(burrowId, ".seeds/issues.jsonl"),
		);
		burrowBody = out.contents;
	} catch (err) {
		if (err instanceof NotFoundError) return { closed: 0, created: 0 };
		throw err;
	}

	const projectBody = (await fs.readFile(projectFile)) ?? "";
	const projectRows = parseSeeds(projectBody);
	const projectIndex = new Map<string, number>();
	for (let i = 0; i < projectRows.length; i++) {
		const row = projectRows[i];
		if (row !== undefined) projectIndex.set(row.id, i);
	}

	let closed = 0;
	let created = 0;
	let changed = false;

	for (const incoming of parseSeeds(burrowBody)) {
		const existingIdx = projectIndex.get(incoming.id);
		if (existingIdx === undefined) {
			projectRows.push(incoming);
			projectIndex.set(incoming.id, projectRows.length - 1);
			changed = true;
			if (incoming.status === "closed") {
				closed += 1;
				await emit("seeds.closed", { id: incoming.id, mode: "added" });
			} else {
				created += 1;
				await emit("seeds.created", { id: incoming.id, status: incoming.status });
			}
			continue;
		}
		if (incoming.status !== "closed") continue;
		const existing = projectRows[existingIdx];
		if (existing === undefined) continue;
		if (existing.status === "closed" && existing.updatedAt >= incoming.updatedAt) continue;
		if (incoming.updatedAt <= existing.updatedAt) continue;
		projectRows[existingIdx] = incoming;
		closed += 1;
		changed = true;
		await emit("seeds.closed", { id: incoming.id, mode: "updated" });
	}

	if (changed) {
		await fs.mkdirp(dirname(projectFile));
		await fs.writeFile(
			projectFile,
			projectRows.length === 0 ? "" : `${projectRows.map((r) => r.raw).join("\n")}\n`,
		);
	}

	return { closed, created };
}

function parseSeeds(body: string): SeedRow[] {
	const out: SeedRow[] = [];
	for (const line of splitLines(body)) {
		try {
			const parsed: unknown = JSON.parse(line);
			if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) continue;
			const obj = parsed as Record<string, unknown>;
			const id = typeof obj.id === "string" ? obj.id : null;
			const status = typeof obj.status === "string" ? obj.status : null;
			const updatedAt = typeof obj.updatedAt === "string" ? obj.updatedAt : "";
			if (id === null || status === null) continue;
			out.push({ id, status, updatedAt, raw: line });
		} catch {
			// skip unparseable lines; we never want to corrupt the project's seeds file.
		}
	}
	return out;
}

/* ----------------------------------------------------------------------- */
/* Plans mirror (warren-d9a2)                                               */
/* ----------------------------------------------------------------------- */

/**
 * Mirror `.seeds/plans.jsonl` from the burrow workspace into the project
 * clone. Append-only: rows whose `id` is absent from the project baseline
 * are appended. Existing rows are never overwritten — plans are immutable
 * once submitted.
 */
export async function mirrorPlans(input: MirrorClosedSeedsInput): Promise<number> {
	const { burrowClient, burrowId, projectPath, fs, emit } = input;
	const projectFile = join(projectPath, ".seeds", "plans.jsonl");

	let burrowBody: string;
	try {
		const out = await withTransportMapping(burrowClient.config, () =>
			burrowClient.http.files.read(burrowId, ".seeds/plans.jsonl"),
		);
		burrowBody = out.contents;
	} catch (err) {
		if (err instanceof NotFoundError) return 0;
		throw err;
	}

	const projectBody = (await fs.readFile(projectFile)) ?? "";
	const projectIds = new Set<string>();
	const projectRows: { id: string; raw: string }[] = [];
	for (const line of splitLines(projectBody)) {
		try {
			const parsed: unknown = JSON.parse(line);
			if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) continue;
			const id = (parsed as Record<string, unknown>).id;
			if (typeof id === "string" && id.length > 0) {
				projectIds.add(id);
				projectRows.push({ id, raw: line });
			}
		} catch {
			// preserve unparseable lines
			projectRows.push({ id: "", raw: line });
		}
	}

	let added = 0;
	for (const line of splitLines(burrowBody)) {
		try {
			const parsed: unknown = JSON.parse(line);
			if (parsed === null || typeof parsed !== "object" || Array.isArray(parsed)) continue;
			const id = (parsed as Record<string, unknown>).id;
			if (typeof id !== "string" || id.length === 0) continue;
			if (projectIds.has(id)) continue;
			projectRows.push({ id, raw: line });
			projectIds.add(id);
			added += 1;
			await emit("seeds.plan_mirrored", { id });
		} catch {
			// skip unparseable lines
		}
	}

	if (added > 0) {
		await fs.mkdirp(dirname(projectFile));
		await fs.writeFile(
			projectFile,
			projectRows.length === 0 ? "" : `${projectRows.map((r) => r.raw).join("\n")}\n`,
		);
	}

	return added;
}

