			outcome: "succeeded",
			repos,
			burrowClientPool: await makePool(fakeBurrowClient(makeBurrow()), repos),
			fs: f.fs,
			exec: fakeExec().exec,
			// no seedsCli
		});

		expect(result.seedIdClosed).toBe(false);
		expect(result.errors.map((e) => e.step)).not.toContain("seed_id_close");
	});
});

